-- Fix CTA button centering in launch-offer-pitch email template
-- The button area was not properly centered in email clients

UPDATE email_templates
SET html_body = E'<!DOCTYPE html>\n<html lang="en">\n<head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"></head>\n<body style="margin:0;padding:0;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',Roboto,''Helvetica Neue'',Arial,sans-serif;background-color:#000;color:#fff;">\n<table width="100%" cellpadding="0" cellspacing="0" style="background-color:#000;"><tr><td align="center" style="padding:40px 20px;">\n<table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;">\n\n<!-- Badge -->\n<tr><td style="padding:0 0 24px;text-align:center;"><div style="display:inline-block;padding:8px 24px;background-color:rgba(57,255,20,0.1);border-radius:50px;border:2px solid #39FF14;"><p style="margin:0;font-size:12px;font-weight:600;color:#39FF14;text-transform:uppercase;letter-spacing:1px;">Founding Tester Offer</p></div></td></tr>\n\n<!-- Main Card -->\n<tr><td style="padding:0;"><div style="padding:40px;background-color:#1F1F1F;border-radius:16px;border:2px solid #39FF14;">\n\n  <h1 style="margin:0 0 24px;font-size:28px;font-weight:bold;color:#fff;line-height:1.2;">Hey {{firstName}},</h1>\n\n  <p style="margin:0 0 16px;font-size:16px;line-height:1.6;color:#E5E5E5;">We just finished building <strong style="color:#fff;">Vibration Fit</strong>, and we''re opening the very first round of our 72&#8209;Hour Activation Intensive to a small group of founding testers.</p>\n\n  <p style="margin:0 0 16px;font-size:16px;line-height:1.6;color:#E5E5E5;">The Activation Intensive is a guided 14&#8209;step path that installs a complete conscious creation system into your life in 72 hours. By the end, you''ll have:</p>\n\n  <p style="margin:0 0 4px;font-size:15px;line-height:1.6;color:#E5E5E5;">&#8226; A written Life Vision across 12 categories</p>\n  <p style="margin:0 0 4px;font-size:15px;line-height:1.6;color:#E5E5E5;">&#8226; Personalized AM/PM audio</p>\n  <p style="margin:0 0 4px;font-size:15px;line-height:1.6;color:#E5E5E5;">&#8226; A vision board</p>\n  <p style="margin:0 0 4px;font-size:15px;line-height:1.6;color:#E5E5E5;">&#8226; A journal started</p>\n  <p style="margin:0 0 4px;font-size:15px;line-height:1.6;color:#E5E5E5;">&#8226; A calibration call booked</p>\n  <p style="margin:0 0 24px;font-size:15px;line-height:1.6;color:#E5E5E5;">&#8226; A 28&#8209;day activation plan to make it all stick</p>\n\n  <p style="margin:0 0 24px;font-size:16px;line-height:1.6;color:#E5E5E5;">Because this is our first live round and we need real feedback, we''re offering two founding tester paths:</p>\n\n  <!-- Activation Intensive Card -->\n  <div style="margin:0 0 16px;padding:24px;background-color:#000;border-radius:12px;border:2px solid #39FF14;">\n    <p style="margin:0 0 4px;font-size:11px;color:#39FF14;text-transform:uppercase;letter-spacing:1px;font-weight:600;">Path 1</p>\n    <p style="margin:0 0 12px;font-size:20px;font-weight:bold;color:#fff;">Activation Intensive</p>\n    <p style="margin:0 0 4px;font-size:14px;color:#E5E5E5;">$499 &#8594; <span style="color:#39FF14;font-weight:700;">$1</span> <span style="color:#999;">(founding tester price)</span></p>\n    <p style="margin:0 0 16px;font-size:14px;line-height:1.6;color:#E5E5E5;font-weight:600;">You get:</p>\n    <table width="100%" cellpadding="0" cellspacing="0">\n      <tr><td style="padding:4px 0;color:#E5E5E5;font-size:14px;"><span style="color:#39FF14;margin-right:8px;">&#10003;</span> Full 72&#8209;Hour Activation Intensive</td></tr>\n      <tr><td style="padding:4px 0;color:#E5E5E5;font-size:14px;"><span style="color:#39FF14;margin-right:8px;">&#10003;</span> 12&#8209;category Life Vision built with VIVA</td></tr>\n      <tr><td style="padding:4px 0;color:#E5E5E5;font-size:14px;"><span style="color:#39FF14;margin-right:8px;">&#10003;</span> Vision Audio (AM/PM), Vision Board, and Journal</td></tr>\n      <tr><td style="padding:4px 0;color:#E5E5E5;font-size:14px;"><span style="color:#39FF14;margin-right:8px;">&#10003;</span> 30&#8209;minute Calibration Call with a coach</td></tr>\n      <tr><td style="padding:4px 0;color:#E5E5E5;font-size:14px;"><span style="color:#39FF14;margin-right:8px;">&#10003;</span> My Activation Plan (your daily roadmap)</td></tr>\n      <tr><td style="padding:4px 0;color:#E5E5E5;font-size:14px;"><span style="color:#39FF14;margin-right:8px;">&#10003;</span> Graduate Unlocks: Advanced Audio Suite, Alignment Gym, and Vibe Tribe</td></tr>\n      <tr><td style="padding:4px 0;color:#E5E5E5;font-size:14px;"><span style="color:#39FF14;margin-right:8px;">&#10003;</span> 8 weeks of Vision Pro membership included</td></tr>\n    </table>\n  </div>\n\n  <!-- Premium Card -->\n  <div style="margin:0 0 24px;padding:24px;background-color:#000;border-radius:12px;border:2px solid #BF00FF;">\n    <p style="margin:0 0 4px;font-size:11px;color:#BF00FF;text-transform:uppercase;letter-spacing:1px;font-weight:600;">Path 2</p>\n    <p style="margin:0 0 12px;font-size:20px;font-weight:bold;color:#fff;">Activation Intensive + Premium Coaching</p>\n    <p style="margin:0 0 16px;font-size:14px;color:#E5E5E5;">$3,000 &#8594; <span style="color:#BF00FF;font-weight:700;">$499</span> <span style="color:#999;">(or 2 payments of $249.50)</span></p>\n    <p style="margin:0 0 12px;font-size:14px;line-height:1.6;color:#E5E5E5;">Everything in Path 1, plus:</p>\n    <table width="100%" cellpadding="0" cellspacing="0">\n      <tr><td style="padding:4px 0;color:#E5E5E5;font-size:14px;"><span style="color:#BF00FF;margin-right:8px;">&#10003;</span> <strong style="color:#BF00FF;">10 private 1:1 coaching sessions over 8 weeks</strong></td></tr>\n      <tr><td style="padding:4px 0;color:#E5E5E5;font-size:14px;"><span style="color:#BF00FF;margin-right:8px;">&#10003;</span> Weeks 1&#8211;2: 2 sessions/week (rapid constraint clearing)</td></tr>\n      <tr><td style="padding:4px 0;color:#E5E5E5;font-size:14px;"><span style="color:#BF00FF;margin-right:8px;">&#10003;</span> Weeks 3&#8211;8: 1 session/week (deepening and integration)</td></tr>\n      <tr><td style="padding:4px 0;color:#E5E5E5;font-size:14px;"><span style="color:#BF00FF;margin-right:8px;">&#10003;</span> Priority support between sessions</td></tr>\n    </table>\n  </div>\n\n  <!-- After Day 56 -->\n  <div style="margin:0 0 24px;padding:16px;background-color:rgba(57,255,20,0.05);border-radius:12px;border:1px solid #333;">\n    <p style="margin:0;font-size:14px;line-height:1.6;color:#E5E5E5;">Both paths include 8 weeks of Vision Pro. After Day 56, it continues at $99 every 28 days. You can cancel anytime before then.</p>\n  </div>\n\n  <!-- Why founding tester -->\n  <p style="margin:0 0 8px;font-size:16px;font-weight:600;color:#fff;">Why these prices?</p>\n  <p style="margin:0 0 32px;font-size:15px;line-height:1.6;color:#E5E5E5;">This is our first round. We need honest feedback, bug reports, and if it genuinely helps you, a testimonial. In exchange, you get founding tester pricing that won''t exist once we launch publicly.</p>\n\n  <!-- CTA -->\n  <table width="100%" cellpadding="0" cellspacing="0">\n    <tr><td align="center" style="padding:0 0 24px;">\n      <p style="margin:0 0 24px;font-size:16px;font-weight:600;color:#fff;">See the full offer and choose your path here:</p>\n      <table cellpadding="0" cellspacing="0" style="margin:0 auto;"><tr>\n        <td align="center" style="background-color:#39FF14;border-radius:50px;">\n          <a href="https://vibrationfit.com/offer/launch" style="display:inline-block;padding:18px 48px;background-color:#39FF14;color:#000;text-decoration:none;font-size:16px;font-weight:700;border-radius:50px;mso-padding-alt:0;text-align:center;">Choose Your Path</a>\n        </td>\n      </tr></table>\n      <p style="margin:20px 0 0;font-size:13px;color:#999;">Spots are limited. Founding tester pricing ends when they''re filled.</p>\n    </td></tr>\n  </table>\n\n  <!-- What we ask -->\n  <p style="margin:0 0 8px;font-size:16px;font-weight:600;color:#fff;">What we ask from you</p>\n  <p style="margin:0 0 4px;font-size:15px;line-height:1.6;color:#E5E5E5;">&#8226; Go through the 72&#8209;hour experience</p>\n  <p style="margin:0 0 4px;font-size:15px;line-height:1.6;color:#E5E5E5;">&#8226; Tell us what you loved, what was confusing, and what you''d change</p>\n  <p style="margin:0 0 24px;font-size:15px;line-height:1.6;color:#E5E5E5;">&#8226; If it helps you, be open to sharing your results</p>\n\n  <p style="margin:0 0 24px;font-size:15px;line-height:1.6;color:#E5E5E5;">If you have any questions, just reply to this email.</p>\n\n  <div style="height:2px;background-color:#39FF14;margin:32px 0;"></div>\n  <p style="margin:0;font-size:15px;line-height:1.6;color:#E5E5E5;">Thank you for helping us get this into the world,<br>Jordan &amp; Vanessa</p>\n\n</div></td></tr>\n\n<!-- Footer -->\n<tr><td style="padding:32px 20px 0;text-align:center;"><p style="margin:0 0 8px;font-size:11px;color:#666;">Vibration Fit &middot; <span style="color:#39FF14;">Above the Green Line</span></p></td></tr>\n\n</table></td></tr></table>\n</body></html>',
    updated_at = NOW()
WHERE slug = 'launch-offer-pitch';
